const status = String($json.status || $json.case_status || 'UNKNOWN').toUpperCase();
const progressRaw = $json.progress;
const progressNum = Number(progressRaw);
const progressText = Number.isFinite(progressNum)
  ? (progressNum <= 1 ? `${Math.round(progressNum * 100)}%` : `${Math.round(progressNum)}%`)
