      message_text: 'В этом деле пока нет документов для удаления',
      reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Добавить документ', callback_data: 'CASE_ADD_DOC' }],[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] })
