const states = data.states || {};
const chatId = String($item(0).$node['Load State'].json.chat_id || 'unknown');
const activeCaseId = String($item(0).$node['Load State'].json.active_case_id || '');

states[chatId] = states[chatId] || {};
states[chatId].pending_action = '';

const raw = $json.data ?? (typeof $json === 'string' ? $json : JSON.stringify($json));
let parsed = {};
try { parsed = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { parsed = {}; }

const ok = !!parsed.ok;
const fileName = $item(0).$node['Prepare Telegram File Path'].json.telegram_document_name || 'document';

if (ok) {
  const docs = Array.isArray(states[chatId].documents) ? states[chatId].documents : [];
  docs.push({
    doc_id: String(parsed.doc_id || '').replace(/^doc_/,''),
    display_doc_id: String(parsed.doc_id || ''),
    name: fileName
  });
  states[chatId].documents = docs;

  const cases = Array.isArray(states[chatId].cases) ? states[chatId].cases : [];
  const selectedCase = cases.find(c => String(c.case_id || c.id || '').replace(/^case_/,'') === activeCaseId);
  if (selectedCase) {
    selectedCase.status = parsed.case_status || 'DIRTY';
    selectedCase.documents_count = Math.max(Number(selectedCase.documents_count || 0), docs.length);
  }
}

data.states = states;

const text = ok
  ? `Документ загружен\n\nФайл: ${fileName}\nДело: ${activeCaseId}\nID документа: <code>${parsed.doc_id || 'неизвестно'}</code>`
  : `Не удалось подтвердить загрузку документа\n\nОтвет API:\n<code>${String(raw).slice(0, 700)}</code>`;

return [{
  json: {
    chat_id: $item(0).$node['Load State'].json.chat_id,
    message_text: text,
    reply_markup_json: JSON.stringify({
      inline_keyboard: [
        [{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],
        [{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]
      ]
    })
  }
}];

