let parsed = {};
try { parsed = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { parsed = {}; }

const escapeHtml = (value) => String(value || '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const answer = String(parsed.answer || '').trim();
if (!answer) {
  return [{
    json: {
      chat_id: $item(0).$node['Load State'].json.chat_id,
      message_text: `Не удалось получить ответ по делу\n\nОтвет API:\n<code>${escapeHtml(String(raw).slice(0, 1000))}</code>`,
      reply_markup_json: JSON.stringify({ inline_keyboard: [[{ text: 'Статус дела', callback_data: 'CASE_STATUS' }, { text: 'Документы', callback_data: 'CASE_LIST_DOCS' }],[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] })
    }
  }];
}

const sources = Array.isArray(parsed.sources) ? parsed.sources : [];
const lines = [];
lines.push('<b>Ответ по делу</b>');
lines.push('');
for (const part of answer.split(/\n+/)) {
  lines.push(escapeHtml(part));
}
if (sources.length) {
  lines.push('');
  lines.push('<b>Источники</b>');
  for (const [i, src] of sources.slice(0, 10).entries()) {
    const name = escapeHtml(src.name || src.doc_name || src.doc_id || `Источник ${i + 1}`);
    const page = src.page !== undefined && src.page !== null ? `, стр. ${escapeHtml(src.page)}` : '';
    lines.push(`• ${name}${page}`);
  }
}
if (parsed.index_version) {
  lines.push('');
  lines.push(`<code>index_version: ${escapeHtml(parsed.index_version)}</code>`);
}

const blocks = [];
let current = '';
const limit = 3500;

const pushCurrent = () => {
  const trimmed = current.trim();
  if (trimmed) blocks.push(trimmed);
  current = '';
};

for (const line of lines) {
  const candidate = current ? `${current}\n${line}` : line;
  if (candidate.length <= limit) {
    current = candidate;
    continue;
  }
  if (current) pushCurrent();

  if (line.length <= limit) {
    current = line;
    continue;
  }

  // fallback: split a single oversized line carefully
  let remaining = line;
  while (remaining.length > limit) {
    let cut = remaining.lastIndexOf(' ', limit);
    if (cut < Math.floor(limit * 0.6)) cut = limit;
    blocks.push(remaining.slice(0, cut).trim());
    remaining = remaining.slice(cut).trim();
  }
  current = remaining;
}
pushCurrent();

return blocks.map((chunk, index) => ({
  json: {
    chat_id: $item(0).$node['Load State'].json.chat_id,
    message_text: chunk,
    reply_markup_json: index === blocks.length - 1 ? JSON.stringify({ inline_keyboard: [[{ text: 'Документы', callback_data: 'CASE_LIST_DOCS' }, { text: 'Статус дела', callback_data: 'CASE_STATUS' }],[{ text: 'Главное меню', callback_data: 'BACK_MAIN' }]] }) : ''
  }
}));

const data = $getWorkflowStaticData('global');
data.states = {};
return items;
